<?php
require_once __DIR__ . '/../../app/customers.php'; require_once __DIR__ . '/../../a9sd8f7sd9f_admin/config.php'; qii_ensure_customer_tables($pdo);
$token=(string)($_GET['token']??$_POST['token']??'');$error='';$done=false;
$stmt=$pdo->prepare("SELECT * FROM customer_action_tokens WHERE token_hash=? AND purpose='password_reset' AND expires_at>NOW() LIMIT 1");$stmt->execute([hash('sha256',$token)]);$row=$stmt->fetch(PDO::FETCH_ASSOC);
if($_SERVER['REQUEST_METHOD']==='POST'&&$row){$password=(string)($_POST['password']??'');if(strlen($password)<8)$error='密码至少 8 位';else{$pdo->prepare('UPDATE customers SET password_hash=? WHERE id=?')->execute([password_hash($password,PASSWORD_DEFAULT),$row['customer_id']]);$pdo->prepare('DELETE FROM customer_action_tokens WHERE id=?')->execute([$row['id']]);$pdo->prepare('DELETE FROM customer_remember_tokens WHERE customer_id=?')->execute([$row['customer_id']]);$done=true;}}
?>
<!doctype html><html lang="zh-CN"><meta charset="UTF-8"><title>重设密码</title><body style="font-family:Arial;background:#fff5fa"><form method="post" style="max-width:430px;margin:60px auto;background:#fff;padding:28px"><h1>重设密码</h1><?php if($done):?><p>密码已更新，<a href="login.php">前往登录</a></p><?php elseif(!$row):?><p>链接无效或已过期。</p><?php else:?><input type="hidden" name="token" value="<?=htmlspecialchars($token)?>"><input name="password" type="password" minlength="8" required style="width:100%;height:44px"><button style="width:100%;height:44px;margin-top:12px;background:#ed4d94;color:#fff;border:0">更新密码</button><p><?=$error?></p><?php endif;?></form></body></html>
